fn deserialize_with_ref<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    let value = Value::deserialize(deserializer)?;

    // Check for $ref syntax
    if let Value::Object(map) = &value {
        if let Some(ref_val) = map.get("$ref") {
            if let Some(ref_str) = ref_val.as_str() {
                // Parse reference like "./a.json#/p_list"
                let parts: Vec<&str> = ref_str.splitn(2, '#').collect();
                if parts.len() == 2 {
                    let file_path = parts[0];
                    let json_path = parts[1];

                    // Read referenced file
                    let content = fs::read_to_string(file_path)
                        .map_err(|e| serde::de::Error::custom(format!("Failed to read {}: {}", file_path, e)))?;

                    // Parse the JSON
                    let root: Value = serde_json::from_str(&content)
                        .map_err(|e| serde::de::Error::custom(format!("Invalid JSON in {}: {}", file_path, e)))?;

                    // Extract the field using simple path traversal for "#/field_name"
                    if let Some(obj) = root.as_object() {
                        if let Some(field) = obj.get(json_path.trim_start_matches('/')) {
                            // Recursively deserialize the found field
                            return Vec::<PathBuf>::deserialize(field.clone().into_deserializer())
                                .map_err(|e| serde::de::Error::custom(format!("Deserialization error: {}", e)));
                        }
                    }
                    return Err(serde::de::Error::custom(format!("Field {} not found in {}", json_path, file_path)));
                }
            }
        }
    }

    // If no $ref, try to deserialize directly
    Vec::<PathBuf>::deserialize(value.into_deserializer())
        .map_err(|e| serde::de::Error::custom(format!("Deserialization error: {}", e)))
}

