//! using `critical_section` and proper memory ordering.
//!
//! On `thumbv6m-none-eabi` (e.g., RP2040 Cortex-M0+), `core::sync::atomic` only provides
//! *lock-free* atomics for 32-bit types on aligned addresses, but *no* native atomic instructions.
//! Thus, `AtomicUsize` operations are implemented using critical sections internally.
//!
//! `Ordering::Relaxed` in a non-atomic context (like inside a critical section) is safe *for this specific use*,
//! but correctness depends on *program semantics*. For a simple channel index increment used for round-robin,
//! `Relaxed` is sufficient — but if you rely on synchronization with other memory operations,
//! `Acquire/Release` may be needed.

// We must disable default features on rp2040 to get thumbv6m-none-eabi compatible build
#![:no_std]

use core::sync::atomic::{AtomicUsize, Ordering};
use critical_section::with;

struct Channel Allocator {
    channel_index: AtomicUsize,
}

impl ChannelAllocator {
    const fn new() -> Self {
        ChannelAllocator {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replaces: `self.channel_index.fetch_add(1, Ordering::Relaxed)`
