    /// and that data must be visible before/after, then use `Acquire`/`Release`.
    /// For a simple counter (like resource index), `Relaxed` is usually sufficient.
    fn fetch_add_channel_index(&self) -> usize {
        with(|_cs| {
            let old = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old + 1, Ordering::Relaxed);
            old
        })
