// We provide a helper function to wrap async closures/
// This is the ergonomic trick: force the user to call into_boxed() on their async fn
pub trait HandlerFnAsyncExt {
    fn into_boxed(self) -> Handler;
}

impl<F, Fut> HandlerFnAsyncExt for F
where
    F: for<'a> Fn(&'a Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
