/// Generates a deterministic pseudorandom 64-bit number using xorshift.
/// Based on the constant-friendly xorshift64* algorithm.
const fn xorshift64_star(state: &mut u64) -> u64 {
    let mut x = *state;
    x ^= x >> 12; // a
    x ^= x << 25; // b
    x ^= x >> 27; // c
