//! executed in an async context, using `std::task::Context` and `Waker`.

use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, Waker};
use std::future::ready;
use tokio::sync::mpsc;

// Define our custom poll result
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// Helper function to create a dummy Waker (safe for polling only, not for waking)
fn dummy_waker() -> Waker {
    // A minimal Waker that does nothing when woken — safe for polling but not for actual wakeups
    // Use `Waker::noop()` since Rust 1.61+
    Waker::noop()
}

// The core function: try to poll a future once without blocking
fn try_poll<X>(future: &mut Pin<Box<dyn Future<Output = X> + '_>>) -> TryPollResult<X>
where
    X: Send + 'static,
{
    // Create a dummy context with a noop Waker
    // This will cause `poll` to return `Pending` only if the future is not ready *yet*
    // but cannot actually schedule a wakeup (which is OK because we only care
    // about whether it's ready *now*).
    let waker = dummy_waker();
    let mut cx = Context::from_waker(&waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // Example 1: Future that is immediately ready
    let mut ready_future = Box::pin(ready(42));
    match try_poll(&mut ready_future) {
        TryPollResult::Ready(val) => println!("Ready future immediately produced: {}", val),
        TryPollResult::Pending => println!("Ready future incorrectly reported pending"),
    }

    // Example 2: Future that will take some time (e.g., delay)
    let delay_fut = tokio::time::sleep(std::time::Duration::from_secs(2));
    let mut delayed_future = Box::pin(delay_fut);
    match try_poll(&mut delayed_future) {
        TryPollResult::Ready(_) => println!("Delay completed already (unlikely!)"),
        TryPollResult::Pending => {
            println!("Delay not ready — spawning task to await it");
            tokio::spawn(async move {
                delayed_future.await;
                println!("Delay completed in background task");
            });
        }
    }

    // Give background task time to complete (but only briefly, since delay is 2s)
    // In real code, you'd likely handle this differently (e.g. forget, join, etc.)
    tokio::time::sleep(std::time::Duration::from_millis(10)).await;
    println!("Main async function exiting.");
