    // Create the main channel
    let (main_tx, main_rx) = mpsc::channel::<Message>();

    // Clone the senders for worker threads
    let keys_tx = main_tx.clone();
    let signals_tx = main_tx.clone();

    // Spawn threads
    let keys_handle = thread::spawn(move || yield_keys(keys_tx));
    let signals_handle = thread::spawn(move || yield_signals(signals_tx));

    println!("Starting event loop. Press 'q' to quit or send SIGINT/SIGTERM.");
    let stdout = io::stdout();
    let mut stdout = stdout.lock();

    // Wait for channel to close or shutdown message
    for msg in main_rx.iter() {
        match msg {
            Message::Key(c) => {
                writeln!(stdout, "Key pressed: '{}'", c).unwrap();
                stdout.flush().unwrap();
