        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // Pre-compute indices to avoid locking in parallel case
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .flat_map(|i| {
                (0..nelems)
                    .filter(move |&j| i < j) // only process each unordered pair once
                    .map(move |j| (i, j))
            })
            .collect();

        // Clear all nb vectors first
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        // Process pairs in parallel
        pairs.par_iter().for_each(|(i, j)| {
            let elem_i = &self.elems[*i];
            let elem_j = &self.elems[*j];
            let dist_sq = elem_i.criterion(&elem_j);

            if dist_sq < cutoff {
