use std::process;

/// Parse an ISO 8601 datetime string (like "2025-08-02T17:35:41.409" or "1970-01-01T00:00:00")
/// into a Unix timestamp (i.e., seconds since epoch).
/// Handles optional fractional seconds (with up to 9 digits), with or without timezone.
/// LanceDB strings appear to be in local/UTC time, so we default to UTC.
pub fn date_string_to_int(d: &str) -> Result<i64, String> {
    // Try parsing with fractional seconds first (LanceDB often includes milliseconds)
    // Try multiple formats to handle varying precision (up to nanoseconds)

    // Attempt 1: With fractional seconds (e.g., "2025-08-02T17:35:41.409", "1970-01-01T00:00:00.000000000")
    // Note: chrono::format doesn't match variable width fraction, so we normalize input

    // Strip potential trailing 'Z' or timezone suffix like "+00:00" just in case
    let trimmed = d.trim();

    // Extract the base datetime part before any timezone (if any)
    let (base, tz) = match trimmed.split_once(&['+', 'Z'][..]) {
        Some((b, tz)) => (b, Some(tz)),
        None => (trimmed, None),
    };

    // Split date and time (by 'T'), then split time by '.' to separate seconds and optional fraction
    let parts: Vec<&str> = base.split('T').collect();
    if parts.len() != 2 {
        return Err(format!("Invalid format: expected 'T' separator in '{}'", d));
    }

    let date_part = parts[0];
    let time_part = parts[1];

    // Split time by '.' to separate seconds and optional fraction
    let time_parts: Vec<&str> = time_part.splitn(2, '.').collect();
    let sec_part = time_parts[0];
    let frac_opt = time_parts.get(1);

    // Check date part is valid (YYYY-MM-DD)
    let date_parts: Vec<&str> = date_part.split('-').collect();
    if date_parts.len() != 3 {
        return Err(format!("Invalid date format in '{}'", d));
    }

    // Parse year/month/day as integers
    let year: i32 = date_parts[0].parse().map_err(|_| format!("Year parsing failed for '{}'", date_parts[0]))?;
    let month: u32 = date_parts[1].parse().map_err(|_| format!("Month parsing failed for '{}'", date_parts[1]))?;
    let day: u32 = date_parts[2].parse().map_err(|_| format!("Day parsing failed for '{}'", date_parts[2]))?;

    // Parse hour:minute:second
    let time_parts: Vec<&str> = sec_part.split(':').collect();
    if time_parts.len() != 3 {
        return Err(format!("Time format invalid in '{}'", sec_part));
    }

    let hour: u32 = time_parts[0].parse().map_err(|_| format!("Hour parsing failed for '{}'", time_parts[0]))?;
    let min: u32 = time_parts[1].parse().map_err(|_| format!("Minute parsing failed for '{}'", time_parts[1]))?;
    let sec: u32 = time_parts[2].parse().map_err(|_| format!("Second parsing failed for '{}'", time_parts[2]))?;

    // Parse fraction (if any)
    let nanosecond = match frac_opt {
        Some(frac_str) => {
            // Pad or truncate to 9 digits for nanoseconds
            let mut frac_digits = frac_str.chars().collect::<Vec<_>>();

            // Truncate to 9 digits if needed
            frac_digits.resize(9, '0');

            let nanos_str: String = frac_digits.iter().collect();
            nanos_str.parse::<u32>().map_err(|e| format!("Fraction parsing failed: {}", e))?  // e.g., "409" -> 409_000_000
        }
        None => 0u32,
    };

    // Build NaiveDateTime and then attach timezone (default to UTC)
    let naive = NaiveDateTime::new(
        chrono:: NaiveDate::from_ymd_opt(year, month, day)
            .ok_or_else(|| format!("Invalid date: {}-{:02}-{:02}", year, month, day))?,
        chrono:: NaiveTime::from_hms_nano_opt(hour, min, sec, nanosecond)
            .ok_or_else(|| format!("Invalid time: {:02}:{:02}:{:02}.{:09}", hour, min, sec, nanosecond))?,
    );

    // Convert to DateTime<Utc>
    let dt = match tz {
        Some("Z") | None => DateTime::<<Utc>>::from_naive_utc_and_offset(naive, Utc),
        Some(tz_str) if tz_str.starts_with('+') || tz_str.starts_with('-') => {
            // Try to parse fixed offset (e.g., "+00:00")
            // For simplicity, treat as UTC offset; implement if needed
            // For now, assume UTC if unknown offset
            DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc)
        }
        _ => DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc)
    };

    Ok(dt.timestamp())
}

fn main() {
    let test_cases = vec![
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
        "2025-08-10T18:31:26.628123",  // 6-digit fraction
        "2025-08-10T18:31:26.628123456", // full nanosecond
        "2025-08-10T18:31:26", // no fraction
