/// Split a shell command string into tokens in a quote-aware fashion.
/// 
/// Handles
/// - unquoted words separated by whitespace
/// - single-quoted strings (respects inner whitespace, but quotes are removed)
/// - concatenation of quoted and unquoted parts (e.g., `' two  'three` → ` two  three`)
/// - leading/trailing whitespace is ignored
pub fn tokenize(s: &str) -> Vec<String> {
    let mut result = Vec::new();
    let mut chars = s.chars().peekable();

    while let Some(c) = chars.next() {
        // Skip leading whitespace
        if c.is_whitespace() {
            continue;
        }

        // Start building a new token
        let mut token = String::new();

        if c == '\'' {
            // Quoted section
            tokenize_quoted(&mut chars, &mut token);
            // Only add non-empty quoted tokens
            if !token.is_empty() {
                result.push(token);
            }
        } else {
            // Unquoted section
            tokenize_unquoted(&mut chars, &mut token, c);
            // Only add non-empty unquoted tokens
            if !token.is_empty() {
                result.push(token);
            }
        }
    }

    result
}

/// Process a double-quoted section (not used in our spec, but included for completeness)
/// According to bash, double quotes also allow some escapes like \$, \", \
, etc.
/// But per specification, we only need to handle single quotes.
#[allow(dead_code)]
fn tokenize_double_quoted<I: Iterator<Item = char>>(chars: &mut std::iter::Peekable<I>, token: &mut String) {
    // Process until closing quote or end of input
    while let Some(c) = chars.next() {
        match c {
            '"' => return, // End of double-quoted string
            \\ => {
                // Escape handling: look ahead and handle specific escapes
                if let Some(next) = chars.peek() {
                    match *next {
                        '"' | '\\' | '$' | '`' | \' => {
                            chars.next(); // consume the next char
                            token.push(*next);
                        }
                        // Other backslash escapes: treat as literal
                        _ => {
                            token.push(c);
                            token.push(*next);
                            chars.next();
                        }
                    }
                } else {
                    token.push(c);
                }
            }
            _ => token.push(c),
        }
    }
}

/// Process a single-quoted section
/// In single quotes, everything is literal — no escapes
fn tokenize_quoted<I: Iterator<Item = char>>(chars: &mut std::iter::Peekable<I>, token: &mut String) {
    // We've already consumed the opening quote
    while let Some(c) = chars.next() {
        match c {
            '\'' => return, // End of single-quoted string
            _ => token.push(c),
        }
    }
}

/// Process an unquoted section
/// Take characters until whitespace
fn tokenize_unquoted<I: Iterator<Item = char>>(
    chars: &mut std::iter::Peekable<I>,
    token: &mut String,
    first_char: char,
) {
    // Add the first character we took
    token.push(first_char);

    // Continue until whitespace or end
    while let Some(&c) = chars.peek() {
        if c.is_whitespace() {
            // End of token
            return;
        } else {
            token.push(chars.next().unwrap());
        }
    }
}
