pub struct SqrtPlusOne;

impl radiate::operation::OpTrait for SqrtPlusOne {
    fn eval(&self, inputs: &[f64]) -> f64 {
        // Ensure exactly one input
        let x = inputs[0];
        // Avoid negative input to sqrt
        if x < 0.0 {
            0.0 // fallback for invalid input
        } else {
            x.sqrt() + 1.0
        }
    }

    fn to_string(&self) -> String {
        "sqrt(x) + 1".to_string()
    }

    fn arity(&self) -> usize {
        1
    }

    fn clone_box(&self) -> Box<dyn radiate::operation::OpTrait> {
        Box::new(self.clone())
    }
}

// We need to convert our custom op into radiate::Op
// Since radiate::Op doesn't allow direct construction of arbitrary ops,
// we use it via Op::func_m (for unary functions) or wrap it.
// But the simpler way in recent versions is to define a custom Op using an adapter.
// However, radiate v0.5 doesn't expose such a constructor directly.

// Alternative: Since `Op` enum is not open, we can use the `Op::func_m` if available.
// If not, the best approach is to patch the function set using the existing API.

// Let's build a solution compatible with the `regression-tree` example pattern.
// In radiate v0.5, Op::func_m exists for unary ops, but requires Fn(f64)->f64 + Clone + 'static.

fn main() {
    // Create a custom operator via Op::func_m (unary function)
    // This is safe because sqrtplusone is stateless and we can represent it as closure.
    let sqrt_plus_one_op = Op::func_m(
        |x| if x < 0.0 { 0.0 } else { x.sqrt() + 1.0 },
        "sqrt(x)+1"
    );

    // Define the function set (same as in the example)
    let store = vec![
        (NodeType::Vertex, vec![
            Op::add(),
            Op::sub(),
            Op::mul(),
            Op::pow(),
            sqrt_plus_one_op,  // Include our custom op
        ]),
        (NodeType::Leaf, vec![Op::var(0)]),
    ];

    // Print to verify
    println!("Custom operator included in store:");
    for (ntype, ops) in &store {
        println!("{:?}: {} ops", ntype, ops.len());
        for op in ops {
            println!("  -> {}", op);
        }
    }

    // Optional: Show usage in a tiny expression tree
    // Use Op::var(0) and Op::func_m to build a tree manually (not GP evolution here, just demo)
