  "main.rs": "use chrono::{DateTime, NaiveDateTime, Utc};

fn date_string_to_int(d: &str) -> Result<i64, String> {
    // Normalize: handle both with and without trailing decimal (milliseconds)
    // LanceDB's ISO format appears like:
    // - "1970-01-01T00:00:00" (no fractional seconds)
    // - "2025-08-02T17:35:41.409" (with milliseconds, but may lack sub-millisecond digits)
    // chrono's `%f` expects 6 digits (microseconds) or more, so we normalize to 6 digits after decimal

    let (base, fracs) = d
        .split_once('.')
        .map(|(b, f)| (b, f))
        .unwrap_or((d, ""));

    // Pad fractional part to exactly 6 digits (microseconds)
    let frac6 = format!("{:<06}", &fracs[..fracs.len().min(6)]).chars().take(6).collect::<String>();
    let normalized = if fracs.is_empty() {
        base.to_string()
    } else {
        format!("{}.{}", base, frac6)
    };

    // Try parsing as NaiveDateTime (no timezone), then attach UTC, then convert to timestamp
    let naive = NaiveDateTime::parse_from_str(&normalized, "%Y-%m-%dT%H:%M:%S%.f")
        .map_err(|e| format!("Failed to parse '{}': {}", d, e))?
        .with_timezone(&Utc);

    Ok(naive.timestamp())
}

