use std::pin::Pin;
use std::task::{Context, Poll, Waker};

use tokio::task::JoinHandle;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Manually polls a future once in a synchronous context.
/// It uses a noop waker that ASCII-prints debug info when woken,
/// but does NOT actually schedule the future for resumption.
/// The future is not allowed to yield (i.e., return Poll::Pending),
/// because without a proper executor context, resuming it won’t work.
fn try_poll<F, X>(future: &mut F) -> TryPollResult<X>
where
    F: Future<Output = X> + Unpin,
{
    // Create a minimal waker that doesn't do anything useful,
    // but satisfies the JIT / compiler for poll.
    struct NoopWaker;
    impl Waker for NoopWaker {
        fn wake(self: std::sync::Arc<Self>) {
            // We intentionally do nothing — this waker is only
            // used to detect final completion, not to resume.
        }

        fn wake_by_ref(self: &std::sync::Arc<Self>) {
            // Same here
        }
    }

    let waker = std::sync::Arc::new(NoopWaker).into();
    let mut cx = Context::from_waker(&waker);

    // SAFETY: we are in a synchronous function (not async), but the
    // `Future` trait’s `poll` method is unsafe because it requires
    // that the waker be valid *and* that the future is pinned.
    // We ensure pinning via `Pin::new_unchecked`, which is safe here
    // because we only poll once and the future lives long enough.
    let mut pinned = Pin::new_unchecked(future);

    match pinned.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // Example 1: Future that's already ready
    let mut ready_fut = tokio::time::duration_until(tokio::time::Duration::from_secs(0));
    match try_poll(&mut ready_fut) {
        TryPollResult::Ready(duration) => {
            println!("Future #1 was ready immediately: {:#?}", duration);
        }
        TryPollResult::Pending => unreachable!("Should be ready"),
    }

    // Example 2: Future that would take time to resolve
    let mut delayed_future = Box::pin(tokio::time::sleep(tokio::time::Duration::from_secs(5)));
    let result = try_poll(&mut delayed_future);
    if let TryPollResult::Pending = result {
        println!("Future #2 is still pending — spawning task to await it.");
        let handle: JoinHandle<()> = tokio::spawn(async move {
            tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
            println!("Delayed future #2 finished in spawned task.");
        });
        // Optional: await the spawned task (not strictly necessary here)
        let _ = handle.await;
    } else {
        panic!("Should have been pending");
    }

    // Example 3: Check with a manual future
    struct Readyi32(i32);
    impl Future for Readyi32 {
        type Output = i32;
        fn poll(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Self::Output> {
            Poll::Ready(std::mem::replace(&mut self.0, -1))
        }
    }

    let mut mfuture = Readyi32(42);
    match try_poll(&mut mfuture) {
        TryPollResult::Ready(val) => println!("Manual future resolved with: {}", val),
        TryPollResult::Pending => unreachable!(),
    }

    // Verify that poll is incomplete if initial poll didn’t return Ready
    // Demo: a future that *always* returns Pending — only safe if you don’t intend to resume it
    struct AlwaysPending;
    impl Future for AlwaysPending {
        type Output = ();
        fn poll(self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<()> {
            Poll::Pending
        }
    }

    let mut always_pending = AlwaysPending;
    match try_poll(&mut always_pending) {
        TryPollResult::Pending => println!("Correctly identified AlwaysPending as pending."),
        TryPollResult::Ready(_) => panic!("Unexpected"),
    }
}
