        transform.rotation = Quat::from_euler(EulerRot::XYZ, 0.0, angle, 0.0);
    }
}

// Raycast simulation for demo: always hits top face at origin
fn update_gizmo(
    block_q: Query<&Transform, With<Block>>,
    mut gizmos: Gizmos,
) {
    // For demonstration, simulate raycast hitting top face
    let hit_normal = Vec3::Y;
    // Simulate center of top face relative to block origin (assuming cube of size 1)
    let block_center = Vec3::ZERO;
    let face_center = block_center + hit_normal * 0.5;

    if let Ok(block_tf) = block_q.get_single() {
        // STEP 1: Get block's basis vectors (its rotated local axes)
        let block_basis = block_tf.compute_visible_basis();
        let block_forward = block_basis.forward();
        let block_up = block_basis.up();

        // STEP 2: We want gizmo to:
        //   - Be placed at face_center
        //   - Have its 'up' direction = hit_normal (to be flush on the face)
        //   - Have its 'forward' direction = projection of block's forward onto plane orthogonal to normal
        //     This makes the gizmo align with the block's orientation in the plane of the face.

        // Compute tangent plane basis:
        // 1. Project block’s forward onto the plane orthogonal to hit_normal
        let projected_forward = (block_forward - hit_normal * block_forward.dot(hit_normal)).normalize();

        // 2. Compute right vector: hit_normal × projected_forward (ensures orthonormal)
        let right = hit_normal.cross(projected_forward).normalize();

        // Build rotation matrix from orthonormal basis: columns are right, up, forward
        // (Bevy’s default gizmo rect is on XY plane with Z as normal, so:
        //  rect's Z=normal, X=right, Y=up)
        let rotation_matrix = Mat3::from_cols(right, hit_normal, projected_forward);
        let target_rotation = Quat::from_mat3(&rotation_matrix);

        // Render gizmo (in white, slightly offset toward normal to avoid z-fighting)
        gizmos.rect(
            Transform::from_translation(face_center + hit_normal * 0.001)
                .with_rotation(target_rotation)
                .to_isometry(),
            Vec2::new(1.0, 1.0),
            Color::WHITE,
        );
    }
}",
