                    let target_value = navigate_json_path(&json, json_path)
                        .ok_or_else(|| serde::de::Error::custom("path not found in referenced JSON"))?;

                    // Deserialize the target value as Vec<PathBuf>
                    serde_json::from_value(target_value)
                        .map_err(|e| serde::de::Error::custom(format!("deserialization error: {}", e)))
