            serde_json::from_value(serde_json::Value::Array(arr))
                .map_err(|e| serde::de::Error::custom(format!("deserialization error: {}", e)))
        }
        _ => Err(serde::de::Error::custom("expected $ref object or array")),
    }
}

fn parse_json_pointer(ref_str: &str) -> Result<(String, Vec<String>), String> {
    // Expected format: "./file.json#/path/to/field"
    // Or absolute URLs like "file:///path/to/file.json#/path"
    let (file_part, json_part_str) = ref_str
        .split_once('#')
        .ok_or_else(|| format!("missing '#' in reference: {}", ref_str))?;

    let json_path = if json_part_str.is_empty() {
        Vec::new()
    } else {
        // Remove leading slash and split by '/'
        let path = json_part_str.trim_start_matches('/')
            .split('/')
            .filter(|s| !s.is_empty())
            .map(|s| {
                // JSON Pointer uses ~1 for / and ~0 for ~
                // Simple case: no escaped chars for our use case
                s.replace("~1", "/").replace("~0", "~")
            })
            .collect::<Vec<String>>();
        path
    };

    Ok((file_part.to_string(), json_path))
}

fn navigate_json_path<'a>(json: &'a serde_json::Value, path: Vec<String>) -> Option<&'a serde_json::Value> {
    let mut current = json;
    for segment in path {
        match current {
            serde_json::Value::Object(map) => {
                current = map.get(&segment)?;
            }
            _ => return None,
        }
    }
    Some(current)
}

