  "main.rs": "use dioxus::prelude::*;
use dioxus::html::geometry::ElementPoint;
use dioxus::events::MouseEvent;

// --- Drag Context ---

#[derive(Clone, Copy, Debug)]
pub struct DragState {
    pub is_dragging: Signal<bool>,
    pub drag_delta: Signal<Option<Coords>>,
}

impl DragState {
    pub fn new() -> Self {
        Self {
            is_dragging: Signal::new(false),
            drag_delta: Signal::new(None),
        }
    }

    pub fn start_drag(&self, original_position: Coords) {
        self.is_dragging.set(true);
        self.drag_delta.set(Some(original_position));
    }

    pub fn update_drag(&self, current_position: Coords) {
        if let Some(original) = *self.drag_delta.read() {
            self.drag_delta.set(Some(Coords {
                x: current_position.x - original.x,
                y: current_position.y - original.y,
            }));
        }
    }

    pub fn end_drag(&self) {
        self.is_dragging.set(false);
        self.drag_delta.set(None);
    }
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub struct Coords {
    pub x: f64,
    pub y: f64,
}

impl Coords {
    pub fn new(x: f64, y: f64) -> Self {
        Self { x, y }
    }
}

// --- Draggable Context Provider ---

#[component]
fn DragProvider(children: Element) -> Element {
    let state = use_context_provider(|| DragState::new());

    rsx! {
        div {
            onmousedown: move |e: MouseEvent| {
                e.stop_propagation();
                e.prevent_default();
                if let Some(coord) = e.element_coordinates() {
                    state.start_drag(Coords {
                        x: coord.x,
                        y: coord.y,
                    });
                }
            },
            onmousemove: move |e: MouseEvent| {
                if *state.is_dragging.read() {
                    e.stop_propagation();
                    if let Some(coord) = e.element_coordinates() {
                        state.update_drag(Coords {
                            x: coord.x,
                            y: coord.y,
                        });
                    }
                }
            },
            onmouseup: move |e: MouseEvent| {
                e.stop_propagation();
                state.end_drag();
            },
            onmouseleave: move |_| {
                state.end_drag();
            },
            style: "position: relative; width: 600px; height: 400px; border: 1px dashed #aaa;",
            {children}
        }
    }
}

// --- Draggable Point ---

#[derive(Clone, PartialEq, Props)]
struct PointProps {
    x: f64,
    y: f64,
    color: String,
}

#[component]
fn DraggablePoint(props: PointProps) -> Element {
    let mut local_coords = use_signal(|| Coords::new(props.x, props.y));
    let drag_state = use_context::::<DragState>();
    let isDragging = use_signal(|| false);

    // Check if we're dragging and compute relative offset
    use_effect(move || {
        if *drag_state.is_dragging.read() {
            if let Some(delta) = *drag_state.drag_delta.read() {
                local_coords.set(Coords {
                    x: props.x + delta.x,
                    y: props.y + delta.y,
                });
            }
        }
    });

    // Sync local dragging state — but *don't* force re-render of whole tree on every move
    // This keeps local_coords reactive only when needed
    use_event!(mousemove, move |e: MouseEvent| {
        if *drag_state.is_dragging.read() {
            if *isDragging.peek() {
                if let Some(coord) = e.element_coordinates() {
                    local_coords.set(Coords {
                        x: coord.x - *drag_state.drag_delta.peek().map(|d| d.x).unwrap_or(0.0),
                        y: coord.y - *drag_state.drag_delta.peek().map(|d| d.y).unwrap_or(0.0),
                    });
                }
            }
        }
    });

    rsx! {
        circle {
            cx: "{local_coords.read().x}",
            cy: "{local_coords.read().y}",
            r: 10,
            fill: "{props.color}",
            onmousedown: move |e: MouseEvent| {
                e.stop_propagation();
                isDragging.set(true);
                let pos = e.element_coordinates().map(|c| Coords { x: c.x, y: c.y });
                if let Some(p) = pos {
                    drag_state.start_drag(p);
                }
            },
            onmouseup: move |_| isDragging.set(false),
            onmouseleave: move |_| isDragging.set(false),
            style: "cursor: grab;",
            onmousemove: move |e: MouseEvent| {
                if *isDragging.read() {
                    e.stop_propagation();
                    e.prevent_default();
                }
            }
        }
    }
}

// --- Main App ---

fn main() {
    dioxus_web::launch(app);
}

fn app() -> Element {
    rsx! {
        DragProvider {
            svg {
                width: "100%",
                height: "100%",
                point1: DraggablePoint { x: 100.0, y: 150.0, color: "blue"},
                point2: DraggablePoint { x: 250.0, y: 100.0, color: "red"},
                point3: DraggablePoint { x: 400.0, y: 250.0, color: "green"},
            }
        }
    }
}
"
}
