  "main.rs": "//! Demonstrates safe replacement of atomic-polyfill::AtomicUsize::fetch_add
//! using `critical_section` and `core::sync::atomic::AtomicUsize` on thumbv6m-none-eabi
//!
//! Note: This is a *demonstration* only. Actual ARMv6-M devices lack native atomic
//! instructions (e.g., LDREX/STREX), so critical-section is required,
//! and relaxed orderings are generally acceptable for simple counters
//! unless shared across cores (which is more complex).

use cortex_m::interrupt;\use core::sync::atomic::{AtomicUsize, Ordering};use critical_section::with;

struct Channel {
    channel_index: AtomicUsize,
}

impl Channel {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replaces: `self.channel_index.fetch_add(1, Ordering::Relaxed)`
    /// There are two correct options depending on semantics:
    ///
    /// 1️⃣  For *single-core*, *interrupt-driven*, or *single-threaded* code
    ///     where only one执行 context matters (the most common case on RP2040):
    ///     - Orderings can be `Relaxed` *if* only the current core accesses this counter
    ///     - BUT for safety *and portability*, use `Ordering::SeqCst` or at least `Ordering::AcqRel`
    ///     - Since RP2040 has two cores, assume concurrent access possible → use stronger ordering.
    ///
    /// 2️⃣  For correct multi-core atomicity on RP2040 (dual-core Cortex-M0+):
    ///     - `critical_section` + *either* `Ordering::SeqCst` *or* `Ordering::AcqRel`
    ///     - `AcqRel` is ideal: it provides both acquire and release semantics internally via critical section.
    ///     - But here we do load→store inside a critical section (i.e., atomic by construction).
    ///     - Since the critical section itself orders everything, we can safely use `Ordering::Relaxed`
    ///       *inside* the critical section — **but only if no other syncing assumptions are needed**.
    ///
    /// Ultimately: `Ordering::Relaxed` is *safe* here *if* the only requirement is “get a unique ID”.
    /// However, using `Ordering::SeqCst` is more conservative and avoids subtle correctness bugs.
    ///
    /// ✅ Recommendation for portability & correctness: use `Ordering::SeqCst`
    ///    (critical_section already ensures mutual exclusion,⟨seqcst⟩ reduces risk).
    fn fetch_and_inc(&self) -> usize {
        with(|_| {
            // RMW operation protected by critical section
            let old_val = self.channel_index.load(Ordering::SeqCst);
            self.channel_index.store(old_val + 1, Ordering::SeqCst);
            old_val
        })
    }
}

fn main() {
    // Simulate usage (not actually runnable on real hardware without `-Z build-std` & probe)
    let channel = Channel::new();

    // Generate a few IDs
    let id0 = channel.fetch_and_inc();
    let id1 = channel.fetch_and_inc();
    let id2 = channel.fetch_and_inc();

    // Terminate cleanly with exit code 0 (emulation; real bare metal would loop_forever)
    // NOTE: This `main` signature works in `cargo run` via `cortex-m-rt` &-semihosting—but on RP2040,
    // you'd need a `panic-halt` or `cortex-m-semihosting` for debug printing.
    // For demo, just assert correctness for testing.
    assert_eq!(id0, 0);
    assert_eq!(id1, 1);
    assert_eq!(id2, 2);

    // Simulate multi-core race condition is *not* tested here
    // (requires real dual-core setup; `critical_section` prevents preemption/interrupts only)
    println!("Replaced fetch_add: IDs [0, 1, 2] produced correctly. ✔");
    // In real bare-metal, you'd use `cortex_m::peripheral::SCB::sys_reset()` or similar
    // but for unit-test purposes, just exit
    std::process::exit(0);
}
"
