fn rewrite_use_tree(edit: &mut TextEdit, tree: ast::UseTree, current_path: Option<String>) {
    let full_path = match (&current_path, tree.path()) {
        (Some(prev), Some(path)) => {
            let segment_str = path_segment_str(path);
            Some(format!("{}{}{}", prev, if prev.is_empty() {""} else {"::"}, segment_str))
        }
        (None, Some(path)) => Some(path_segment_str(path)),
        (prev, None) => prev.clone(),
    };

    // Handle glob (`*`) or rename (`.. as ..`) or wildcard (`_`) at the end
    let is_simple_reexport = tree.star_token().is_some() || tree.underscore_token().is_some();

    // Check if the full path starts with "vexide::devices::"
    if let Some(ref path_str) = full_path {
        if path_str.starts_with("vexide::devices::") {
            let chop_prefix = "vexide::devices::";
            let remainder = &path_str[chop_prefix.len()..];

            // Build replacement
            let replacement = if remainder.is_empty() {
                "vexide::".to_string()
            } else {
                format!("vexide::{}", remainder)
            };

            // Only rewrite if original tree has a path (not just `*` or `_`)
            if let Some(path) = tree.path().filter(|_| !is_simple_reexport) {
                replace_path(edit, path, &replacement);
            }

            // If it was e.g. `use vexide::devices::{smart, adi}`, children stay at current level
            if let Some(list) = tree.use_tree_list() {
                for child in list.use_trees() {
                    rewrite_use_tree(edit, child, Some("vexide".to_string()));
                }
            }
            return;
        }
        // Also handle `vexide::devices` -> `vexide` when not nested further
        if path_str == "vexide::devices" {
            let path = tree.path().expect("must have path if we matched");
            replace_path(edit, path, "vexide");
            // Promote children
            if let Some(list) = tree.use_tree_list() {
                for child in list.use_trees() {
                    rewrite_use_tree(edit, child, Some("vexide".to_string()));
                }
            }
            return;
        }
    }

    // Regular recursion: just promote existing path or `vexide` if it's root
    let promoted_path = match full_path.as_deref() {
        Some("vexide") => Some("vexide".to_string()),
        Some(_) => full_path,
        None => None,
    };

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            rewrite_use_tree(edit, child, promoted_path.clone());
        }
    }
}

fn path_segment_str(path: ast::Path) -> String {
    path.segments()
        .map(|seg| seg.syntax().to_string().trim().to_string())
        .collect::<Vec<_>>()
        .join("::")
}

fn replace_path(edit: &mut TextEdit, old_path: ast::Path, replacement: &str) {
    let start = old_path.syntax().text_range().start();
    let len = old_path.syntax().text_len();
    edit.insert(start, replacement.to_string());
    edit.delete(TextRange::new(start, start + len));
}
"
}

