use std::sync::mpsc::{self, Sender, Receiver};
use std::thread;
use std::time::Duration;

use expectrl::{Pty, Command, Session, Error};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Start a simple interactive shell (e.g., bash) to test with
    let mut pty = Pty::open()?;
    let mut cmd = Command::new("bash")
        .spawn()?;

    // Lose the child handle — PTY is now fully managed
    pty.connect_to_command(&mut cmd)?;

    // Create a sender for write commands
    let (write_tx, write_rx): (Sender<String>, Receiver<String>) = mpsc::channel();

    // SPAWN WRITER THREAD — owns the PTY for writing
    {
        let write_pty = pty.clone();\        let tx = write_tx.clone();
        thread::spawn(move || {
            let mut pty = write_pty;
            while let Ok(data) = tx.recv() {
                if let Err(e) = pty.write_all(data.as_bytes()) {
                    eprintln!("Write error: {e}");
                    break;
                }
            }
        });
    }

    // SPAWN READER THREAD — owns the PTY for reading (non-blocking)
    {
        let mut pty = pty;
        // Set PTY to non-blocking
        use libc::{fcntl, F_SETFL, O_NONBLOCK};
        let fd = pty.as_raw_fd();
        unsafe {
            let flags = fcntl(fd, libc::F_GETFL, 0);
            fcntl(fd, libc::F_SETFL, flags | O_NONBLOCK);
        }

        thread::spawn(move || {
            let mut buf = [0u8; 4096];
            loop {
                match pty.read(&mut buf) {
                    Ok(0) => {
                        eprintln!("PTY EOF — terminal exited");
                        break;
                    }
                    Ok(n) => {
                        let chunk = std::str::from_utf8(&buf[..n])
                            .unwrap_or("(non-UTF8)");
                        print!("{}", chunk);
                        std::io::stdout().flush().ok();
                    }
                    Err(ref e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                        // No data available — sleep a tiny bit to avoid tight loop
                        thread::sleep(Duration::from_millis(10));
                    }
                    Err(e) => {
                        eprintln!("Read error: {e}");
                        break;
                    }
                }

                // Non-blocking poll of incoming writes
                if let Ok(s) = write_rx.try_recv() {
                    // Try to write directly — if blocked or error, ignore
                    let _ = pty.write_all(s.as_bytes());
                }
            }
        });
    }

