struct RequestHandler;

#[async_trait::async_trait]
impl RequestStage for RequestHandler {
    async fn stage1(&self, ctx: Arc<Mutex<opentelemetry::Context>>) {
        // Rehydrate tracing span from opentelemetry::Context
        let span = get_span_from_context(&ctx, "stage1").await;
        let _enter = span.enter();

        println!("[STAGE1] doing work");
        tokio::time::sleep(tokio::time::Duration::from_millis(5)).await;
    }

    async fn stage2(&self, ctx: Arc<Mutex<opentelemetry::Context>>) {
        let span = get_span_from_context(&ctx, "stage2").await;
        let _enter = span.enter();

        println!("[STAGE2] doing work");
        tokio::time::sleep(tokio::time::Duration::from_millis(5)).await;
    }

    async fn upstream(&self, ctx: Arc<Mutex<opentelemetry::Context>>) {
        let span = get_span_from_context(&ctx, "upstream").await;
        let _enter = span.enter();

        println!("[UPSTREAM] making request");
        tokio::time::sleep(tokio::time::Duration::from_millis(5)).await;
    }
}

async fn get_span_from_context(ctx: &Arc<Mutex<opentelemetry::Context>>, name: &str) -> tracing::Span {
    let ctx_guard = ctx.lock().await;
    let otel_cx = tracing_opentelemetry::OpenTelemetryContext::from_context(*ctx_guard.clone());

    // Extract the current span from the stored OpenTelemetry context
    // If present, it's the parent of the new span we'll create
    let parent = otel_cx.span().span_context().clone();

    // Create a new span with explicit parent from the context
    span!(
        Level::DEBUG,
        name,
        otel.kind = "internal",
        otel.status_code = "unset",
        parent = parent,
    )
}

#[tokio::main]
async fn main() {
    // Set up tracing + OpenTelemetry pipeline
    let collector = Registry::default()
        .with(tracing_subscriber::fmt::layer().with_target(false))
        .with(tracing_opentelemetry::layer().with_tracer(
            opentelemetry::sdk::trace::Tracer::builder()
                .with_exporter(opentelemetry::sdk::export::trace::stdout::new_collector_stdout())
                .build(),
