use serde::Deserialize;
use std::fmt;

// Define the types
#[derive(Debug, Default, Serialize, Deserialize)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
enum B {
    #[default]
    Variant1,
    Variant2(u32),
    Variant3 { name: String, value: i32 },
}

// Custom visitor for A
struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("struct A with fields 'x' and 'b'")
    }

    fn visit_map<V>(self, mut map: V) -> Result<Self::Value, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<&str>()? {
            match key {
                "x" => {
                    if x.is_some() {
                        return Err(V::Error::duplicate_field("x"));
                    }
                    x = Some(map.next_value()?);
                }
                "b" => {
                    if b.is_some() {
                        return Err(V::Error::duplicate_field("b"));
                    }
                    // Delegate deserialization of b to serde's built-in Vec<B> visitor
                    b = Some(map.next_value()?);
                }
                _ => {
                    // Skip unknown fields
                    map.next_value::<serde::de::IgnoredAny>()?;
                }
            }
        }

        let x = x.ok_or_else(|| V::Error::missing_field("x"))?;
        let b = b.unwrap_or_default(); // default to empty vec if missing

        Ok(A { x, b })
    }
}

// Implement custom deserializer for A
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
