struct DummyWaker;

impl Wake for DummyWaker {
    fn wake(&self) {
        // Do nothing
    }
}

unsafe fn dummy_raw_waker() -> RawWaker {
    fn clone(ptr: *const ()) -> RawWaker {
        RawWaker::new(ptr, &VTABLE)
    }

    fn wake(_ptr: *const ()) {
        // Do nothing
    }

    fn wake_by_ref(_ptr: *const ()) {
        // Do nothing
    }

    fn drop(_ptr: *const ()) {
        // Do nothing
    }

    static VTABLE: RawWakerVTable = RawWakerVTable::new(
        clone,
        wake,
        wake_by_ref,
        drop
    );

    RawWaker::new(ptr::null(), &VTABLE)
}

fn try_poll<X>(future: &mut (impl Future<Output = X> + Unpin)) -> TryPollResult<X> {
    // SAFETY: We create a dummy waker that is safe to use
    let waker = std::task::Waker::from(Arc::new(DummyWaker));
    let mut cx = Context::from_waker(&waker);

    let mut pinned = std::pin::pin!(future);
    match Pin::new(&mut pinned).poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

