    // Test 1: Already-completed future
    let fut1 = async { 42 };
    let mut f1 = fut1;
    match try_poll(&mut f1) {
        TryPollResult::Ready(x) => {
            println!("Fut1 ready synchronously: {}", x);
        }
        TryPollResult::Pending => {
            println!("Fut1 was pending (should not happen for already-completed future)");
        }
    }

    // Test 2: A future that will definitely yield (sleep for 1ms)
    let fut2 = tokio::time::sleep(std::time::Duration::from_millis(1));
