pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    // Match both with and without fractional seconds
    // Try format without fractional seconds first
    if d.chars().filter(|&c| c == '.').next().is_none() {
        // Format: "YYYY-MM-DDTHH:MM:SS"
        let dt = DateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S")
            .map_err(|_| FlusterError::FailToParseDate)?;
