        // Format: "YYYY-MM-DDTHH:MM:SS.fff"
        // Chrono supports up to 9 digits of fractional seconds with %f, but 
        // trailing zeros may be present, so normalize by splitting on '.'
        let parts: Vec<&str> = d.splitn(2, '.').collect();
        if parts.len() < 2 {
