  "main.rs": "use axum::{
    extract::ws::{WebSocket, WebSocketUpgrade},
    http::{header, HeaderValue, Method, StatusCode},
    response::IntoResponse,
    routing::get,
    Router,
};
use axum_extra::extract::TypedHeader;
use std::net::SocketAddr;
use tracing_subscriber::EnvFilter;

#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::fmt::init()
        .with_env_filter(EnvFilter::from_default_env());

    // Allowed origin for WebSocket connections
    const ALLOWED_ORIGIN: &str = "https://www.example.com";

    // Define the origin-checking layer
    let app = Router::new()
        .route("/ws", get(ws_handler))
        .layer(axum::middleware::from_fn(move |
            req: axum::extract::Request,
            next: axum::middleware::Next,
        |) async move {
            // Only enforce origin check on WebSocket upgrade requests
            if req.headers().get(axum::http::header::UPGRADE) == Some("websocket") {
                let origin = req.headers().get(header::ORIGIN).cloned();

                let allowed = origin.map_or(false, |o| {
                    o == ALLOWED_ORIGIN || o == HeaderValue::from_static(ALLOWED_ORIGIN)
                });

                if !allowed {
                    return Err(StatusCode::FORBIDDEN);
                }
            }

            Ok::<_, StatusCode>(next.run(req).await)
        });

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    tracing::info!("listening on {}", addr);
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}

async fn ws_handler(
    ws: WebSocketUpgrade,
    TypedHeader(origin): TypedHeader<header::Origin>,
) -> impl IntoResponse {
    // Double-check origin (for defense in depth)
    if origin.as_str() != ALLOWED_ORIGIN {
        return Err(StatusCode::FORBIDDEN);
    }

    Ok(ws.on_upgrade(handle_socket))
}

async fn handle_socket(mut socket: WebSocket) {
    while let Some(msg) = socket.recv().await {
        if msg.is_err() {
            break;
        }

        let msg = msg.unwrap();
        if msg.is_text() {
            if let Ok(text) = msg.to_str() {
                tracing::info!("Received message: {}", text);
                // Echo back
                let _ = socket.send(axum::extract::ws::Message::text(text)).await;
            }
        }
    }
}
