struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    pub fn build_lists(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // Reset neighbor lists
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        // Iteration: for each element i, check all j > i to avoid duplicates
        // and to avoid self-comparison.
        // We collect the neighbor *indices* first, then populate neighbor lists.
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .flat_map(|i| {
                (i + 1..nelems)
                    .filter_map(move |j| {
                        let dist_sq = self.elems[i].criterion(&self.elems[j]);
                        if dist_sq < cutoff {
                            Some((i, j))
                        } else {
                            None
                        }
                    })
            })
            .collect();

        // Finally, populate neighbor lists using the found pairs
        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }
    }

    pub fn build_lists_parallel(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;
        let elems_ref = &self.elems;

        // Reset neighbor lists in parallel-safe way
        // (we use sequential here since clearing is cheap and avoids borrow issues)
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        // Parallel generation of neighbor pairs (i, j) with i < j
        let pairs: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
            .flat_map(|i| {
                let mut local_pairs = Vec::new();
                for j in (i + 1)..nelems {
                    let dist_sq = elems_ref[i].criterion(&elems_ref[j]);
                    if dist_sq < cutoff {
                        local_pairs.push((i, j));
                    }
                }
                local_pairs
            })
            .collect();

        // Populate mutual neighbors (sequential for safety)
        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }
    }
