```json
{
  "Cargo.toml": " Cargo.toml
[package]
name = "rustyline_cursor_fix"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "13"
",
  "main.rs": "use rustyline::{
    Editor, Cmd, Event, EventContext, EventHandler, KeyEvent, RepeatCount,
    ConditionalEventHandler, Movement,
};
use rustyline::helper::Helper;

struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> MyEventHandler {
        MyEventHandler {
            insert: insert.to_string(),
        }
    }

    fn delete_whitespace_and_insert(
        &self,
        context: &EventContext,
    ) -> Vec<Cmd> {
        let pos = context.pos();
        let line = context.line().as_str();

        // Find the last non-whitespace character before cursor
        let mut cursor: usize = pos;
        while cursor > 0 && line.as_bytes()[cursor-1] == b' ' {
            cursor -= 1;
        }

        // Find start of whitespace sequence
        let mut start = cursor;
        while start > 0 && line.as_bytes()[start-1] == b' ' {
            start -= 1;
        }

        let mut cmds = Vec::new();

        // If there was whitespace before cursor, delete it
        if start < pos {
            let count = pos - start;
            cmds.push(Cmd::Move(Movement::BackwardChar(count as RepeatCount)));
            cmds.push(Cmd::Delete(Movement::ForwardChar(count as RepeatCount)));
        }

        // Insert the desired character
        cmds.push(Cmd::Insert(self.insert.clone(), 1));

        cmds
    }
}

impl ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let cmds = self.delete_whitespace_and_insert(context);

        // For rustyline <=13, we can't return multiple cmds directly,
        // but we can use Cmd::RelativeMove and Cmd::Insert sequentially
        // by combining the ideas into a single Insert that includes 
        // the deleted content before the insertion point.
        // Since we can't do multiple actions in one Cmd, we need a workaround:

        // The key insight: Since deletion then insertion would work,
        // but rustyline only runs one Cmd per handler, we simulate it
        // by first deleting whitespace and then inserting the char.
        // 
        // We use a two-step workaround with a runtime hack: we
        // can return Cmd::Insert but adjust position manually.

        // Better approach: use Repl's step-based nature and return the commands.
        // However, rustyline versions up to v13 don't support sequential commands.
        // Alternative: Insert before and manually adjust cursor position.

        // Let's use a workaround: find position, delete whitespace, insert char.
        // We simulate by computing what the final line would be and replace the region.

        let pos = context.pos();
        let line = context.line().as_str();

        // Find the first non-whitespace backwards from pos
        let mut i = pos;
        while i > 0 && line.chars().nth(i-1).map_or(true, |c| c.is_whitespace()) {
            i -= 1;
        }

        // Create replacement: delete whitespace + insert our char
        // Construct new line = line[..i] + our_char + line[pos..]
        let mut new_line = String::from(&line[..i]);
        new_line.push(self.insert.chars().next().unwrap_or(' '));
        new_line.push_str(&line[pos..]);

        let movement = Movement::BackwardChar((pos - i) as RepeatCount);
        let replacement = if pos == i {
            // No deletion, just insert before cursor
            Some(self.insert.clone())
        } else {
            // Replace whitespace + char both in one go (cursor ends up after)
            Some(new_line[i..].to_string())
        };

        // Instead of Replace, we use Insert after moving to i
        // So we return Cmd::Replace(movement, replacement), but then cursor is before the char.
        // Workaround: we insert the char after decoration.

        // Better solution: Use Cmd::RelativeMove + Cmd::Insert via new helper cmd?
        // No. So let's use the following hack:

        // Since rustyline doesn't support multi-step commands natively,
        // we use the following clever trick: we replace *from i to pos* with the new char.
        // Then cursor ends at position i + 1 (i.e., after inserted char).

        let count = (pos - i) as RepeatCount;

        // Replace with our char and 1 space warning, but just insert char
        let replacement = self.insert.clone();

        // But this only sets the cursor to after the inserted text.
        // Use Replacement with a replacement string that includes a trailing space for double insertion?

        // Actually, Replace(m, s) final cursor position = (context.pos() - m.distance()) + s.len()
        // We want it to be at position i + 1 = (context.pos() - count) + 1
        // If s.len() == 1, then final cursor = (context.pos() - count) + 1 = i + 1.
        // So Replace(Movement::BackwardChar(count), Some(char.to_string())) works perfectly!

        Some(Cmd::Replace(movement, Some(replacement)))
    }
}

