  "main.rs": "//! Test demonstrating safe replacement of `AtomicUsize::fetch_add` using `critical_section`
//! for `thumbv6m-none-eabi` (e.g., rp2040).
//!
//! Since `AtomicUsize::fetch_add` is not available on `thumbv6m-none-eabi` (Mos nc64bit compare-and-swap)
//! and `atomic-polyfill` is unmaintained, we use `critical_section` with correct memory ordering.
//!
//! **Important**: The correct orderings are:
//!   - `load(Ordering::SeqCst)`
//!   - `store(..., Ordering::SeqCst)`
//!
//! Why? `fetch_add` is a read-modify-write operation. Its behavior must be sequentially consistent
//! to preserve the *atomicity* and *global visibility* of the increment — otherwise, races may
//! cause lost updates or incorrect values across threads (cores).
//!
//! For pure single-core readers (e.g., only one reading core), Relaxed *might* be sufficient,
//! but as a drop-in replacement for `fetch_add`, SeqCst is the only safe choice.

use core::sync::atomic::{AtomicUsize, Ordering};
use critical_section::with;

struct ChannelAllocator {
    channel_index: AtomicUsize,
}

impl ChannelAllocator {
    const fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    fn alloc_channel(&self) -> usize {
        // Safe & correct replacement for `fetch_add(1, Ordering::Relaxed)` on thumbv6m-none-eabi.
        // ReplaceRelaxed → SeqCst because:
        // - `fetch_add` is a read-modify-write; its semantics include a *total ordering*.
        // - Many users (including drivers and RTOS primitives) expect `fetch_add` to be sequentially consistent.
        // - Thumbv6M has no native RMW atomic ops, so critical-section alone *is* the synchronization,
        //   but semantics of the higher-level operation (atomic fetch-and-increment) require global consistency.
        with(|_| {
            let old = self.channel_index.load(Ordering::SeqCst);
            self.channel_index.store(old + 1, Ordering::SeqCst);
            old
        })
    }
}

fn main() {
    let allocator = ChannelAllocator::new();

    // Simulate concurrent access via sequential critical sections (not truly concurrent on single-core,
    // but mimics what would happen on dual-core rp2040).
    // On rp2040, each core would use same `allocator` instance with independent `critical_section` implementation.

    let idx0 = allocator.alloc_channel();
    let idx1 = allocator.alloc_channel();
    let idx2 = allocator.alloc_channel();

    assert_eq!(idx0, 0);
    assert_eq!(idx1, 1);
    assert_eq!(idx2, 2);

    println!("✅ Atomic fetch_add replacement works correctly with SeqCst.");
}
"
