use std::sync::Arc;
use std::thread;
use std::time::Duration;
use std::sync::mpsc::{self, Sender, Receiver, TryRecvError};
use std::sync::atomic::{AtomicBool, Ordering};

use termion::input::TermRead;
use termion::raw::RawTerminal;
use termion::event::Key;
use termion::input::MouseTerminal;
use termion::screen::AlternateScreen;
use termion::input::Keys;
use signal_hook::consts::signal::*;
use signal_hook::iterator::Signals;
use signal_hook::flag;

// Define message types
#[derive(Debug)]
enum Message {
    Key(char),
    Signal(Signal),
    Shutdown,
    Error(String),
}

// Helper to convert std::io::Error to Message::Error
fn io_result<T, E: std::fmt::Debug>(res: Result<T, E>) -> Option<T> {
    match res {
        Ok(v) => Some(v),
        Err(e) => {
            eprintln!("IO error: {:?}", e);
            None
        }
    }
}

// Yields key events until shutdown flag is set
fn yield_keys(
    sender: Sender<Message>,
    shutdown: Arc<AtomicBool>,
) {
    // Set up stdin
    let mut stdin = termion::console::TermRead stdin::stdin();

    // Use alternate screen because we're in raw mode
    let mut stdout = io::stdout();
    io_result(stdout.execute(termion::screen::ToAlternateScreen)).ok();
    io_result(stdout.execute(termion::raw::IntoRawMode)).ok();

    let mut buffer = String::new();

    while !shutdown.load(Ordering::Relaxed) {
        // Poll for keys with timeout to avoid blocking forever
        let mut selected = stdin.keys();
        if let Some(Ok(key)) = selected.next() {
            match key {
                Key::Char('q') => {
                    // Signal shutdown on 'q'
                    sender.send(Message::Shutdown).ok();
                    break;
                }
                Key::Char(c) => {
                    sender.send(Message::Key(c)).ok();
                }
                Key::Backspace => {
                    sender.send(Message::Key('\x08')).ok();
                }
                Key::Delete => {
                    sender.send(Message::Key('\x7f')).ok();
                }
                Key::Enter => {
                    sender.send(Message::Key('\n')).ok();
                }
                _ => {}
            }
        }

        // Small sleep to prevent busy waiting (10ms)
        thread::sleep(Duration::from_millis(10));
    }

    // Restore terminal state
    io_result(stdout.execute(termion::screen::ToMainScreen)).ok();
    io_result(stdout.execute(termion::raw::IntoRawMode)).ok();
}

// Yields signals until shutdown flag is set
fn yield_signals(
    sender: Sender<Message>,
    shutdown: Arc<AtomicBool>,
) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    while !shutdown.load(Ordering::Relaxed) {
        if let Some(sig) = signals.pending() {
            // If any signal is pending, process it
            for s in sig {
                sender.send(Message::Signal(s)).ok();
                if s == SIGINT || s == SIGTERM {
                    // On interrupt/terminate, send shutdown
                    sender.send(Message::Shutdown).ok();
                    break;
                }
            }
        }
        thread::sleep(Duration::from_millis(10));
    }
}

// Main function
fn main() {
    // Shared shutdown flag
    let shutdown = Arc::new(AtomicBool::new(false));

    // Channel for event messages
    let (sender, receiver): (Sender<Message>, Receiver<Message>) = mpsc::channel();

    // Clone sender for each thread
    let key_sender = sender.clone();
    let signal_sender = sender.clone();
    let shutdown_for_key = shutdown.clone();
    let shutdown_for_signal = shutdown.clone();

    // Start key listener thread
    let key_thread = thread::spawn(move || yield_keys(key_sender, shutdown_for_key));

    // Start signal listener thread
    let signal_thread = thread::spawn(move || yield_signals(signal_sender, shutdown_for_signal));

    // Event loop
    println!("Event loop started. Press 'q' to quit, or press Ctrl+C/Ctrl+\\.");
    println!("Press any key to see it echoed here.");

    'outer: loop {
        match receiver.try_recv() {
            Ok(msg) => {
                match &msg {
                    Message::Key(c) => {
                        print!("Key: {}\n", c);
                        io::stdout().flush().ok();
                    },
                    Message::Signal(sig) => {
                        println!("Signal: {:?}", sig);
                        // Short-circuit to exit on signal
                        if *sig == SIGINT || *sig == SIGTERM {
                            break 'outer;
                        }
                    },
                    Message::Shutdown => {
                        println!("Received shutdown signal.");
                        break 'outer;
                    }
                    Message::Error(_) => {}
                }
            }
            Err(TryRecvError::Empty) => {
                // No message, continue loop
                thread::sleep(Duration::from_millis(10));
            }
            Err(TryRecvError::Disconnected) => {
                println!("Channel disconnected. Exiting.");
                break 'outer;
            }
        }
    }

    // Signal shutdown to threads
    shutdown.store(true, Ordering::Relaxed);

    // Wait for threads to finish
    key_thread.join().ok();
    signal_thread.join().ok();

    println!("Cleanup complete.");
}
"
