name = "shell_tokenizer"
version = "0.1.0"
edition = "2021"

[dependencies]
itertools = "0.12"",
  "main.rs": "use itertools::Itertools;

fn tokenize(s: &str) -> Vec<String> {
    s.split("'")
        .enumerate()
        .map(|(i, part)| {
            if i % 2 == 0 {
                // Non-quoted parts: split into space-groupings and non-space-groupings
                part.chars()
                    .group_by(|&c| c == ' ')
                    .into_iter()
                    .map(|(is_space, chars)| {
                        if is_space {
                            None // We'll filter these out later
                        } else {
                            Some(chars.collect::<String>())
                        }
                    })
                    .collect::<Vec<_>>()
            } else {
                // Quoted parts: keep entire part as-is
                vec![Some(part.to_string())]
            }
        })
        .flatten()
        // Filter out None values (space-only groups)
        .filter_map(|x| x)
        .collect()
}

fn main() {
    let test_cases = vec![
        " one  ' two  'three    four",
        " 'one'  ' two  'three    four",
        "hello world",
        "'hello world'",
        "  'quoted  spaces' unquoted",
    ];

    for test in test_cases {
        let tokens = tokenize(test);
        println!("Input: {:?}", test);
        println!("Tokens ({}):", tokens.len());
        for (i, token) in tokens.iter().enumerate() {
            println!("  [{}]: <{}>", i, token);
        }
        println!();
    }
}
"
}
