fn flipflop(s: Type, r: Type) -&gt; (Type, Type) {
    let mut s2 = Local::behavior_subject::&lt;bool, Infallible&gt;(false);
    let mut r2 = Local::behavior_subject::&lt;bool, Infallible&gt;(false);

