pub fn wrap_async_fn_once<F, Fut>(f: F) -> impl for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
where
    F: for<'a> FnOnce(&'a mut Context) -> Fut + Send + 'static,
