    }
}

impl Clone for CartesianIterator {
    fn clone(&self) -> Self {
        Self {
            dims: self.dims.clone(),
            current: self.current.clone(),
            done: self.done,
        }
    }
}

impl Iterator for CartesianIterator {
    type Item = usize;

    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }
