fn rewrite_use_tree(tree: UseTree) -> Option<UseTree> {
    match tree.kind() {
        // `vexide::devices::X` or `vexide::devices::smart::Motor`
        ast::UseTreeKind::Path(base_path, inner_tree_opt) => {
