// e.g., `vexide::devices::smart::Motor` → `vexide::smart::Motor`
fn rewrite_path(path: &ast::Path) -> Option<ast::Path> {
    let mut segments: Vec<_> = path.segments().collect();
    let mut i = 0;

    // Trim any leading `vexide::devices` → `vexide`
    if segments.len() > 1
        && segments[0].as_str() == Some("vexide")
        && segments[1].as_str() == Some("devices")
    {
