        segments.remove(1); // Remove `devices`
        i = 1; // Avoid double-processing
    }

    let mut new_segments = Vec::new();
    for (idx, seg) in segments.iter().enumerate() {
        if idx == 1 && idx == i && seg.as_str() == Some("devices") {
            continue; // Skip devices again if missed
        }
        new_segments.push(seg.clone());
    }

    if new_segments.len() != segments.len() {
