// Helper: check if `self` (tree) is under `vexide::devices`
fn ends_with_devices(path: &ast::Path) -> bool {
    let mut segs: Vec<_> = path.segments().collect();
    if segs.len() < 2 {
        return false;
    }

    segs.pop(); // drop last segment

    if segs.is_empty() {
        return false;
    }
    segs.pop() == Some(make::path_segment(make::name_ref("devices")))
}

