// Utility: make path from list of segments
fn make_path(segments: Vec<ast::PathSegment>) -> ast::Path {
    use ra_ap_syntax::ast::make::path;
    path(segments)
}

// Extend `SyntaxNode` with convenience replacement
trait ReplaceSyntax {
    fn replace_with(&self, new: SyntaxNode);
}

impl ReplaceSyntax for SyntaxNode {
    fn replace_with(&self, new: SyntaxNode) {
        let parent = self.parent().unwrap();
        let idx = self
            .siblings()
            .position(|s| s == *self)
            .unwrap_or(0);
        parent
            .children_with_tokens()
            .nth(idx)
            .unwrap_or_else(|| panic!("replace_with: invalid index {}", idx))
