// Fake API version header
#[derive(Debug, Clone, Copy)]
pub enum APIVersion {
    V1,
    V2,
}

impl std::str::FromStr for APIVersion {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s {
            "v1" => Ok(APIVersion::V1),
            "v2" => Ok(APIVersion::V2),
            _ => Err(format!("Unknown version: {}", s)),
        }
    }
}

#[derive(Debug)]
pub struct ApiVersionHeader(pub APIVersion);

impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(
        parts: &mut axum::extract::Parts,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let name = header::HEADER_NAME::from_static("x-api-version");
        let value = parts.headers.get(&name)
            .ok_or_else(|| APIError::InvalidInput("Missing X-Api-Version header".to_string()))?
            .to_str()
            .map_err(|_| APIError::InvalidInput("Invalid X-Api-Version header value".to_string()))?;

        let version = value.parse::<APIVersion>()
            .map_err(|e| APIError::InvalidInput(format!("Invalid version: {}", e)))?;

        Ok(ApiVersionHeader(version))
    }
}

