        APIVersion::V1 => "v1",
        APIVersion::V2 => "v2",
    };
    info!("API version: {}", version_str);

    // Self-revocation allowed for everyone
    if access_claims.sub != revoke_user.user_id {
        // Only admin can revoke other users
        access_claims.validate_role_admin()?;
    }

    // In real life: revoke user tokens
    let _ = state.counter.fetch_add(1, Ordering::SeqCst);

