fn try_poll<T, F>(future: &mut F, waker: &Waker) -> TryPollResult<T>
where
    F: Future + Unpin,
    F::Output: Unpin,
{
    let mut pinned = Pin::new(future);
    let mut context = Context::from_waker(waker);

    match pinned.as_mut().poll(&mut context) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

