fn tokenize(s: &str) -> Vec<String> {
    s.split('\'')
        .enumerate()
        .map(|(i, part)| {
            if i % 2 == 0 {
                // Even-indexed: non-quoted portions
                // Split into space vs non-space runs
                part.chars()
                    .group_by(|&ch| ch == ' ')
                    .into_iter()
                    .map(|(is_space, chars)| (is_space, chars.collect::<String>()))
                    .collect::<Vec<_>>()
            } else {
                // Odd-indexed: quoted portions (keep as-is)
                vec![(false, part.to_string())]
            }
        })
        .flatten()
        // Group consecutive non-space runs together
        .group_by(|(is_space, _)| *is_space)
        .into_iter()
        .filter_map(|(is_space, grp)| {
            if is_space {
                // Skip pure space groups
                None
            } else {
                // Concatenate all non-space parts
                Some(grp.map(|(_, s)| s).collect::<String>())
            }
        })
        .collect()
}

