    // Write the raw binary data directly (no base64)
    handle.write_all(data).unwrap();

    flush_output(&mut handle);
}

fn flush_output(handle: &mut io::StdoutLock<'_>) {
    // Ensure we flush *before* potential buffer overflows
    handle.flush().unwrap();
}

fn create_shared_memory(size: usize) -> MmapMut {
    // Use memmap2::MmapMut::map_anon for anonymous shared memory
    MmapMut::map_anon(size).expect("Failed to create shared memory")
}

fn main() {
    let (width, height) = termion::terminal_size().unwrap_or((80, 24));
    let width = width as usize;
    let height = height as usize;

    // Each pixel: RGB (3 bytes), padded to 4 bytes for alignment
    let bytes_per_pixel = 4;
    let pitch = width * bytes_per_pixel;
    let img_size = pitch * height;

    // Create shared memory buffer
    let mut mmap = create_shared_memory(img_size);

    // Get an FD for Kitty graphics (optional; we'll use raw binary)
    let stdout = io::stdout();
    let mut handle = stdout.lock();

    // First, query Kitty to ensure proper capabilities (safe to ignore error)
    // This is optional—commented to keep it simple
    // let _ = execute!(handle, tablet_query);

    let mut time: f32 = 0.0;
    let mut image_id: u32 = 1; // Use image ID 1 for animation
    let mut frame_count: u32 = 0;

    loop {
        // Generate frame into shared memory
        for y in 0..height {
            let row = &mut mmap[y * pitch..(y + 1) * pitch];
            for x in 0..width {
                let idx = x * 4;
                let fx = x as f32 / width as f32;
                let fy = y as f32 / height as f32;

                let r = ((fx * std::f32::consts::PI + time).sin() * 0.5 + 0.5) * 255.0;
                let g = ((fy * std::f32::consts::PI + time * 1.3).sin() * 0.5 + 0.5) * 255.0;
                let b = (((fx + fy) * std::f32::consts::PI + time * 0.7).sin() * 0.5 + 0.5) * 255.0;

                row[idx] = r as u8;
                row[idx + 1] = g as u8;
                row[idx + 2] = b as u8;
                row[idx + 3] = 255; // Alpha = 255
            }
        }

        // Flush and signal frame update using Kitty raw binary mode
        // Use 'a=T' (transmit raw RGB without base64 encoding)
        // With 'm=1', Kitty expects raw format immediately after the control string.
        // Format: <ESC>_Ga=T,m=1,i=ID;SIZE<ESC>\<raw_data><ESC>\
        // size is number of raw bytes (not including padding)
        let raw_data = &mmap[0..width * height * 3]; // 24-bit RGB
        let cmd = format!(
            "\x1b_Ga=T,m=1,i={};{}\x1b\\",
            image_id,
            raw_data.len()
        );

        handle.write_all(cmd.as_bytes()).unwrap();
        handle.write_all(raw_data).unwrap();
        handle.flush().unwrap();

        // Optional: extract from shared memory if Kitty needs cleanup certificates, but not needed here

        time += 0.1;
        frame_count += 1;

        // Break after ~100 frames for testing (remove for production)
        if frame_count > 100 {
            break;
        }

        // Sleep for ~60fps (~16.67ms)
        std::thread::sleep(std::time::Duration::from_millis(16));
    }
}
