const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of pixels horizontally in-place.
/// Each pixel is 4 bytes; we reverse the order of 4-byte pixels by swapping chunks.
/// Maximum portability + safe+sound performance:
/// - Uses `swap_nonoverlapping` to avoid bounds checking per-byte
/// - Compiler will likely optimize to efficient load/store pairs or even vectorized code
#[inline]
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);
    let mut left = 0;
    let mut right = line_bytes.len().saturating_sub(BYTES_PER_PIXEL);

