  "main.rs": "use azure_core::{TokenCredentials, BearerTokenAuthenticationPolicy};
use azure_storage::StorageCredentials;
use azure_storage_blobs::prelude::*;
use reqwest::{Client, StatusCode};
use serde::{Deserialize, Serialize};
use std::env;
use std::sync::Arc;
use tokio::fs::File;
use tokio::io::{AsyncReadExt, AsyncWriteExt};

// ───────────────────────────────────────────────────────────────────────────────────────────────
// Data structures
// ───────────────────────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Deserialize, Serialize)]
struct TradeData {
    id: u64,
    symbol: String,
    price: f64,
    quantity: f64,
    time: u64,
}

// ───────────────────────────────────────────────────────────────────────────────────────────────
// Token acquisition
// ───────────────────────────────────────────────────────────────────────────────────────────────

#[derive(Deserialize)]
struct TokenResponse {
    access_token: String,
    expires_in: u64,
}

async fn get_oauth_token(
    tenant_id: &str,
    client_id: &str,
    client_secret: &str,
) -> Result<String, String> {
    let token_url = format!("https://login.microsoftonline.com/{}/oauth2/v2.0/token", tenant_id);
    let client = Client::new();

    let res = client
        .post(&token_url)
        .form(&[
            ("grant_type", "client_credentials"),
            ("client_id", client_id),
            ("client_secret", client_secret),
            ("scope", "https://storage.azure.com/.default"),
        ])
        .send()
        .await
        .map_err(|e| format!("Token request failed: {e}"))?;

    if res.status() != StatusCode::OK {
        let body = res.text().await.unwrap_or_else(|_| "(empty)".into());
        return Err(format!(
            "Token endpoint returned {} - body: {}",
            res.status(),
            body
        ));
    }

    let token_res: TokenResponse = res
        .json()
        .await
        .map_err(|e| format!("Failed to parse token JSON: {e}"))?;

    Ok(token_res.access_token)
}

// ───────────────────────────────────────────────────────────────────────────────────────────────
// Core blob fetching with concurrent downloads and minimal allocations
// ───────────────────────────────────────────────────────────────────────────────────────────────

const MAX_CONCURRENT_DOWNLOADS: usize = 64;

async fn process_blobs(
    container_client: Arc<ContainerClient>,
    prefix: String,
) -> Result<Vec<TradeData>, String> {
    let mut trades = Vec::new();

    // List blobs page-by-page, and for each page spawn downloads with concurrency limit
    let mut list = container_client
        .list_blobs()
        .prefix(prefix)
        .into_stream();

    while let Some(page) = list.next().await {
        let page = page.map_err(|e| format!("List blobs page failed: {e}"))?;
        let blob_names: Vec<String> = page
            .blobs
            .blobs
            .into_iter()
            .filter(|b| b.name.ends_with(".json"))
            .map(|b| b.name)
            .collect();

        let downloads: Vec<_> = blob_names
            .into_iter()
            .map(|name| {
                let container_client = container_client.clone();
                async move {
                    let blob_client = container_client.blob_client(&name);
                    match blob_client.get_content().await {
                        Ok(bytes) => match serde_json::from_slice::<TradeData>(&bytes) {
                            Ok(trade) => Ok::<TradeData, String>(trade),
                            Err(e) => {
                                eprintln!("JSON parse error for {name}: {e}");
                                Err(format!("JSON parse error for {name}: {e}"))
                            }
                        },
                        Err(e) => {
                            eprintln!("Download failed for {name}: {e}");
                            Err(format!("Download failed for {name}: {e}"))
                        }
                    }
                }
            })
            .collect();

        // Limit concurrency per page to avoid overwhelming the system
        let chunked = downloads
            .chunks(MAX_CONCURRENT_DOWNLOADS)
            .map(|chunk| {
                futures::future::join_all(chunk)
                    .map(|results| {
                        results
                            .into_iter()
                            .filter_map(|r| match r {
                                Ok(t) => Some(t),
                                Err(_) => None,
                            })
                            .collect::<Vec<_>>()
                    })
            })
            .collect::<Vec<_>>();

        for res in futures::future::join_all(chunked).await {
            trades.extend(res);
        }
    }

    Ok(trades)
}

async fn fetch_trades_from_azure() -> Result<Vec<TradeData>, String> {
    let start = std::time::Instant::now();
    eprintln!("[LOG] Starting fetch_trades_from_azure");

    let tenant_id = env::var("AZURE_TENANT_ID").map_err(|e| e.to_string())?;
    let client_id = env::var("AZURE_CLIENT_ID").map_err(|e| e.to_string())?;
    let client_secret = env::var("AZURE_CLIENT_SECRET").map_err(|e| e.to_string())?;
    let storage_account = env::var("AZURE_ACCOUNT_NAME").map_err(|e| e.to_string())?;
    let container_name = env::var("AZURE_CONTAINER_NAME").map_err(|e| e.to_string())?;
    let prefix_opt = env::var("AZURE_PREFIX_OPT").map_err(|e| e.to_string())?;
    let prefix_fut = env::var("AZURE_PREFIX_FUT").map_err(|e| e.to_string())?;

    let auth_start = std::time::Instant::now();
    let token = get_oauth_token(&tenant_id, &client_id, &client_secret).await?;
    eprintln!(
        "[LOG] Authentication took {:.2} seconds",
        auth_start.elapsed().as_secs_f32()
    );

    let bearer_token = TokenCredentials::new(token);
    let auth_policy = BearerTokenAuthenticationPolicy::new(bearer_token);

    let container_client = Arc::new(
        BlobServiceClient::new(storage_account, StorageCredentials::anonymous())
            .with_policy(auth_policy)
            .container_client(container_name),
    );

    let list_start = std::time::Instant::now();
    eprintln!("[LOG] Listing & downloading blobs...");

    // Process prefixes concurrently
    let trades_opt = { 
        let container = container_client.clone();
        let prefix = prefix_opt;
        tokio::spawn(async move { process_blobs(container, prefix).await }) 
    };
    let trades_fut = { 
        let container = container_client;
        let prefix = prefix_fut;
        tokio::spawn(async move { process_blobs(container, prefix).await }) 
    };

    let trades_opt = trades_opt.await.map_err(|e| e.to_string())??;
    let trades_fut = trades_fut.await.map_err(|e| e.to_string())??;

    let total_time = start.elapsed().as_secs_f32();
    let trades: Vec<TradeData> = trades_opt.into_iter().chain(trades_fut).collect();
    eprintln!(
        "[LOG] Downloaded {} trades in {:.2} seconds",
        trades.len(),
        total_time
    );

    Ok(trades)
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::init();

    let trades = fetch_trades_from_azure().await.map_err(|e| {
        eprintln!("Error: {e}");
        e
    })?;

    // Just for demonstration - print first trade
    if let Some(t) = trades.first() {
        println!("First trade: {:#?}", t);
    }

    Ok(())
}
