use libc::{fcntl, O_NONBLOCK};

// Non-blocking reader for PTY
struct NonBlockingReader {
    fd: i32,
}

impl NonBlockingReader {
    fn new(fd: i32) -> io::Result<Self> {
        unsafe {
            // Set FD to non-blocking
            let flags = fcntl(fd, libc::F_GETFL, 0);
            if flags == -1 {
                return Err(io::Error::last_os_error());
            }
            if fcntl(fd, libc::F_SETFL, flags | O_NONBLOCK) == -1 {
                return Err(io::Error::last_os_error());
            }
        }
        Ok(Self { fd })
    }

    fn read_nonblocking(&self, buf: &mut [u8]) -> io::Result<usize> {
        match unsafe { libc::read(self.fd, buf.as_mut_ptr() as *mut _, buf.len() as _) } {
            n if n >= 0 => Ok(n as usize),
            _ => {
                let err = io::Error::last_os_error();
                // EWOULDBLOCK/EAGAIN is normal for non-blocking reads
                if err.kind() == io::ErrorKind::WouldBlock {
                    Ok(0)
                } else {
                    Err(err)
                }
            }
        }
    }
}

fn main() {
