    let pty_fd = process.get_pty_fd();

    // Wrap PTY for non-blocking reads
    let reader = Arc::new(NonBlockingReader::new(pty_fd).expect("Failed to set non-blocking"));

    // Create producer/consumer channel for writes
    let (tx_write, rx_write): (Sender<String>, Receiver<String>) = unbounded();

    // Read thread: continuously polls PTY without blocking on lock
    let reader_clone = Arc::clone(&reader);
    thread::spawn(move || {
        let mut buf = [0u8; 4096];
        loop {
            match reader_clone.read_nonblocking(&mut buf) {
                Ok(0) => {
                    // No data *and* EOF (process ended)
                    let _ = process.wait();
                    break;
                }
                Ok(n) => {
                    if n > 0 {
                        let s = String::from_utf8_lossy(&buf[..n]).to_string();
