use bevy::render::texture::{Image, ImageDescriptor, TextureFormat};
use bevy::ptr::PinnedVecU8;
use futures_lite::future;
use std::collections::HashMap;
use std::io::{Cursor, Read, Seek, SeekFrom};
use std::pin::Pin;

/// A simple mock "WAD-like" archive format:
/// [u8; 4] magic ("WAD3")
/// [u32; 1] num_entries
/// for each entry:
///   [u32; 4] offset
///   [u32; 4] size
///   [u8; 32] name (null-terminated)
/// Then collects all data at the end (not needed for this demo).
///
/// This is a *minimal* demonstration — real WAD/GoldSrc handling needs full parsing.

const MAGIC: &[u8] = b"WAD3";

/// Minimal ZIP-like virtual filesystem for lazy loading
#[derive(Asset, TypePath, Default)]
struct LazyWadAsset {
    /// Pseudo-filesystem like `"my_wad.wad///textures/my_texture.png"`
    entries: HashMap<String, PinnedVecU8>,
}

/// A custom loader for our lazy asset type
#[derive(Default)]
struct LazyWadLoader;

#[derive(Debug, Error)]
enum WadLoadingError {
    #[error("Invalid WAD magic")]
    InvalidMagic,
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
}

impl AssetLoader for LazyWadLoader {
    fn extensions(&self) -> &[&str] {
        &["wad"]
    }

    async fn load(
        &self,
        reader: &mut Reader,
        _path: std::path::PathBuf,
        _load_context: &mut LoadContext,
    ) -> Result<(), bevy::asset::LoadError> {
        let mut buf = Vec::new();
        reader.read_to_end(&mut buf).await?;

        if &buf[0..4] != MAGIC {
            return Err(WadLoadingError::InvalidMagic.into());
        }

        let num_entries = u32::from_le_bytes([buf[4], buf[5], buf[6], buf[7]]) as usize;
        let mut entries: HashMap<String, PinnedVecU8> = HashMap::new();

        let mut cursor = Cursor::new(&buf[8..]);
        for _ in 0..num_entries {
            let mut offset_bytes = [0u8; 4];
            let mut size_bytes = [0u8; 4];
            let mut name_bytes = [0u8; 32];

            cursor.read_exact(&mut offset_bytes)?;
            cursor.read_exact(&mut size_bytes)?;
            cursor.read_exact(&mut name_bytes)?;

            let offset = u32::from_le_bytes(offset_bytes) as usize;
            let size = u32::from_le_bytes(size_bytes) as usize;

            // Parse null-terminated name
            let name_end = name_bytes.iter().position(|&b| b == 0).unwrap_or(32);
            let name = String::from_utf8_lossy(&name_bytes[..name_end]).to_string();

            // Store just a *deferral* pointer — don’t read data yet!
            let entry_data = buf[offset..offset + size].to_vec();
            entries.insert(name, PinnedVecU8::from(entry_data));
        }

        let mut asset = LazyWadAsset { entries };
        // Return full asset ( eventual Bevy will still need to handle *dependency assets*
        // but this gives us control over which sub-assets get materialized)
        _load_context.set_default_asset(LoadedAsset::new(asset));
        Ok(())
    }
}

