    fn extensions(&self) -> &[&str] {
        &["wad_tex"] // our special extension for *lazy* texture references
    }

    async fn load(
        &self,
        _reader: &mut Reader,
        path: std::path::PathBuf,
        load_context: &mut LoadContext,
    ) -> Result<(), bevy::asset::LoadError> {
        // e.g., path = "assets/nested_wad.wad///textures/stone.png.wad_tex"
