unsafe impl Send for SimpleWaker {}
unsafe impl Sync for SimpleWaker {}

fn try_poll<X>(future: &mut Pin<Box<dyn Future<Output = X> + '_>>) -> TryPollResult<X> {
    // Create a dummy waker and context
    let waker = Waker::from(Arc::new(SimpleWaker));
    let mut cx = Context::from_waker(&waker);

    // SAFETY: We're not moving the future out of the `Box`, so pinning is preserved
    match Pin::new(future).as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    // Example 1: a future that's already ready
    let mut ready_future = Box::pin(async { 42 });
    match try_poll(&mut ready_future) {
        TryPollResult::Ready(val) => println!("Ready immediately: {}", val),
        TryPollResult::Pending => {
            // Would never happen for a ready future
            println!("Pending (unexpected)");
        }
    }

    // Example 2: a future that will yield (e.g., sleep or oneshot)
    let (tx, rx) = oneshot::channel::<i32>();
    let mut pending_future = Box::pin(rx);

    match try_poll(&mut pending_future) {
        TryPollResult::Pending => {
            println!("Future is pending — spawning a task to await it...");

            // Spawn a task to poll the future properly in async context
            tokio::spawn(async move {
                match tokio::time::timeout(tokio::time::Duration::from_secs(5), pending_future).await {
                    Ok(Ok(val)) => println!("Task received value: {}", val),
                    Ok(Err(e)) => println!("Oneshot was dropped: {}", e),
                    Err(_) => println!("Timeout waiting for value"),
