use tokio::sync::{OnceCell, Mutex};
use tokio_postgres::{Client, NoTls};

// Minimal example: demonstrating safe caching of tokio_postgres::Client
// without closing the connection.

// The key is:
// 1. The Client must be held in a long-lived structure.
// 2. The Connection must NOT be spawned with plain tokio::spawn.
//    Instead, it should be handled in the background via an async task
//    that shares ownership (e.g., Arc<Mutex<_>>) and is kept alive
//    as long as the Client exists.
// 3. Avoid spawning standalone tasks for the Connection that are not
//    tied to the Client's lifetime.

pub struct DbConfig {
    pub port: u16,
    pub user: String,
    pub password: String,
}

pub struct CachedDbConnection {
    config: Arc<DbConfig>,
    master_client: Arc<Mutex<Option<Client>>>,
}

impl CachedDbConnection {
    pub fn new(config: DbConfig) -> Self {
        Self {
            config: Arc::new(config),
            master_client: Arc::new(Mutex::new(None)),
        }
    }

    // Get or initialize connection to the 'postgres' default DB
    pub async fn get_master_client(&self) -> Arc<Mutex<Option<Client>>> {
        let existing = self.master_client.lock().await;
        if existing.is_none() {
            drop(existing); // release lock before spawning
            let client = self.connect_to(&None).await.unwrap();
            *self.master_client.lock().await = Some(client);
        }
        Arc::clone(&self.master_client)
    }

    async fn connect_to(&self, db_name: &Option<&str>) -> Result<Client, tokio_postgres::Error> {
        let mut conn_str = format!(
            "host=localhost port={} user={} password={}",
            self.config.port, self.config.user, self.config.password
        );
        if let Some(name) = db_name {
            conn_str.push_str(&format!(" dbname={}", name));
        }

        let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

        // CRITICAL: Keep connection in a background task scoped to the app
        // but don't use Arc<Mutex<Option<_>>> for the connection itself.
        // Instead, spawn a task that waits on *conn*.
        tokio::spawn(async move {
            if let Err(e) = conn.await {
                eprintln!("Connection closed: {}", e);
            }
        });

        Ok(client)
    }

    // Run a SQL statement (e.g., CREATE/DROP) on the master DB or a specific DB.
    // This clones the Client via Arc, so no new connection is made.
    pub async fn run_on_master(&self, sql: &str) -> Result<(), tokio_postgres::Error> {
        let guard = self.master_client.lock().await;
        let client = guard.as_ref().expect("Master client must be initialized");
        client.execute(sql, &[]).await?;
        Ok(())
    }

    pub async fn run_on_db(&self, db_name: &str, sql: &str) -> Result<(), tokio_postgres::Error> {
        // Use dedicated client for DB operations, not cached — this avoids
        // interfering with the master connection.
        let client = self.connect_to(&Some(db_name)).await?;
        client.execute(sql, &[]).await?;
        Ok(())
    }
}

