fn resolve_ref(ref_path: &str) -> Result<ResolvedPathList, serde::de::Error> {
    // Parse reference format: "相对于当前文件路径的减少 ./a.json#/p_list"
    let parts: Vec<&str> = ref_path.split('#').collect();
