// A point that listens to context and updates itself when dragged
#[derive(Props, Clone)]
pub struct PointProps {
    pub x: f64,
    pub y: f64,
    #[props(default)]
    pub r: f64,
}

#[component]
fn DragPoint(props: PointProps) -> Element {
    let ctx = use_context::<DragContext>().expect("Missing DragProvider");

    // Local signal: position of the point
    let x = use_signal(|| props.x);
    let y = use_signal(|| props.y);

    // If dragging, read the delta from the start position to current
    // But we need the start position!
    // Let's record start position on mousedown locally, not in context
    let start_x = use_signal(|| 0.0);
    let start_y = use_signal(|| 0.0);
    let is_point_dragging = use_signal(|| false);

    let onmousedown = move |evt: MouseEvent| {
        evt.stop_propagation();
        evt.prevent_default();
        if let Some(pos) = evt.element_coordinates() {
            ctx.is_dragging.set(true);
            ctx.currentMouse.set(pos);
            start_x.set(*x.read());
            start_y.set(*y.read());
            is_point_dragging.set(true);
        }
    };

    let onmouseup = move |_| {
        is_point_dragging.set(false);
    };

    // Subscribe to context drag changes only if this point is dragging
    let dragging = *is_point_dragging.read();
    let current = *ctx.currentMouse.read();

    if dragging {
        // Compute delta from start position to current mouse
        let dx = current.x - start_x.read().clone();
        let dy = current.y - start_y.read().clone();
        x.set(props.x + dx);
        y.set(props.y + dy);
    }

    rsx! {
        circle {
            cx: "{x.read()}",
            cy: "{y.read()}",
            r: "{props.r}",
            fill: "steelblue",
            onmousedown: onmousedown,
            onmouseup: onmouseup,
        }
    }
}

