// Reusable list property using downcasting of inner items
pub fn list_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool)
where
    T: Default + 'static,
{
    egui::CollapsingHeader::new(title)
        .default_open(true)
        .enabled(interactable)
        .show(ui, |ui| {
            ui.horizontal_top(|ui| {
                if ui.button("➕ Add").clicked() {
                    value_mut.push(T::default());
                }
            });

            let mut i = 0;
            while i < value_mut.len() {
                ui.horizontal(|ui| {
                    // Note: We use `Any` to pass the element to `downcast_property`
                    let element_ref: &mut dyn Any = &mut value_mut[i];
                    downcast_property(ui, "", element_ref, interactable);

                    if ui.button("❌").on_hover_text("Remove").clicked() {
                        value_mut.remove(i);
                    } else {
                        i += 1;
                    }
                });
            }
        });
}

// Reusable option property
pub fn option_property<T>(ui: &mut Ui, title: &str, value_mut: &mut Option<T>, interactable: bool)
where
    T: Default + 'static,
{
    let mut is_option_none = value_mut.is_none();

    ui.horizontal(|ui| {
        ui.label(title);
        ui.add_space(8.0);
        bool_property(ui, "None", &mut is_option_none, interactable);
        ui.add_space(2.0);

        if is_option_none {
            *value_mut = None;
        } else if let Some(inner) = value_mut.as_mut() {
            // Pass inner to downcast_property by wrapping into `dyn Any`
            let inner_any: &mut dyn Any = inner;
            downcast_property(ui, "", inner_any, interactable);
        } else {
            *value_mut = Some(T::default());
        }
    });
}

