fn update_gizmo(
    query: Query<(&Transform, &GlobalTransform), With<CubeRotation>>,
    mut gizmos: Gizmos,
) {
    if let Ok((xf, global_xf)) = query.get_single() {
        // Simulate hitting the *positive X* face of the cube
        // In world space, positive X is represented by xf.right()
        let hit_normal = xf.right(); // World-space face normal
        let position = xf.translation; // Cube center
        let face_center = position + hit_normal * 0.5;

