        //   * The gizmo's current Up (Y) remains as close as possible to world Up (Y)
        //     (to avoid unnecessary roll around Z)
        //
        // The strategy: create a rotation that aligns (Z) to normal,
        // but constrained to the plane defined by normal and world Up.

        let origin = Vec3::Z;
        let target = hit_normal.normalize();

        // Compute a rotation that maps Z to target
        // Use from_rotation_arc, but guard against colinearity
        let base_rotation = if target.abs_diff_eq(Vec3::Z, 1e-5) {
            Quat::IDENTITY
        } else if target.abs_diff_eq(-Vec3::Z, 1e-5) {
            // Flip 180° around X or Y — choose X to avoid gimbal issues
            Quat::from_rotation_x(PI)
