        // Apply the base rotation to world Up (Y), and check the angle to actual Up
        let candidate_up = base_rotation * Vec3::Y;
        let projected = (candidate_up - candidate_up.dot(target) * target).normalize();
        let world_up_proj = (Vec3::Y - Vec3::Y.dot(target) * target).normalize();

        let rotation_around_normal = if projected.abs_diff_eq(Vec3::ZERO, 1e-5)
            || world_up_proj.abs_diff_eq(Vec3::ZERO, 1e-5)
        {
            Quat::IDENTITY
        } else {
