            let angle = projected.angle_to(world_up_proj);
            let sign = if (projected.cross(world_up_proj)).dot(target) < 0.0 {
                -1.0
            } else {
                1.0
            };
            Quat::from_axis_angle(target, sign * angle)
        };

        // Final orientation: align Z→normal, and minimize roll
        let final_rotation = rotation_around_normal * base_rotation;

        // Draw gizmo at face center, flush with surface
        gizmos.rect(
            Transform::from_translation(face_center + hit_normal * 0.01)
                .with_rotation(final_rotation)
                .to_isometry(),
